def gen(rng, size):
    n = max(3, min(size, 100000))
    k = rng.randint(0, 1000000000)
    nums = []
    for _ in range(n):
        if rng.random() < 0.5:
            nums.append(rng.randint(0, max(0, k - 1)))
        else:
            nums.append(rng.randint(0, 1000000000))
    return [nums, k]

