class Solution:
    def minIncrementOperations(self, nums, k):
        n = len(nums)
        qualifying = [x >= k for x in nums]
        cost = [max(0, k - x) for x in nums]
        idxs = [i for i in range(n) if not qualifying[i]]
        m = len(idxs)
        best = float('inf')
        for mask in range(1 << m):
            state = qualifying[:]
            total = 0
            for j in range(m):
                if mask & (1 << j):
                    state[idxs[j]] = True
                    total += cost[idxs[j]]
            run = 0
            ok = True
            for v in state:
                if v:
                    run = 0
                else:
                    run += 1
                    if run >= 3:
                        ok = False
                        break
            if ok and total < best:
                best = total
        return best

