class Solution:
    def minIncrementOperations(self, nums, k):
        INF = float('inf')
        dp0, dp1, dp2 = 0, INF, INF
        for x in nums:
            boost = max(0, k - x)
            m = min(dp0, dp1, dp2)
            dp0, dp1, dp2 = m + boost, dp0, dp1
        return min(dp0, dp1, dp2)

