var minIncrementOperations = function(nums, k) {
    const INF = Infinity;
    let dp0 = 0, dp1 = INF, dp2 = INF;
    for (const x of nums) {
        const boost = Math.max(0, k - x);
        const m = Math.min(dp0, dp1, dp2);
        const ndp0 = m + boost;
        const ndp1 = dp0;
        const ndp2 = dp1;
        dp0 = ndp0; dp1 = ndp1; dp2 = ndp2;
    }
    return Math.min(dp0, dp1, dp2);
};
